import { useState } from 'react';
import axios from 'axios';
import "./styles.css";

export const FileUploader = ({}) => {
    const [file, setFile] = useState(null);
    const [image, setImage] = useState(null);

    const onInputChange = (e) => {
        setFile(e.target.files[0])
        document.getElementById('response').setAttribute("hidden", "hidden")
        document.getElementById('fileName').innerHTML = e.target.files[0].name
    };

    const onSubmit = (e) => {
        e.preventDefault();
        const data = new FormData();
        data.append('file', file);
        axios.post('//ec2-54-173-51-94.compute-1.amazonaws.com/upload', data, {
            responseType: "arraybuffer"
          })
        .then((res) => {
            const base64 = btoa(
                new Uint8Array(res.data).reduce(
                  (data, byte) => data + String.fromCharCode(byte),
                  ''
                )
              )
            setImage(base64)
            document.getElementById('response').removeAttribute("hidden")
        })
        .catch((err) => {
            document.getElementById('response').setAttribute("hidden", "hidden")
        })
    };

    return (
    <center>
     <form method="post" onSubmit={onSubmit}>
        <table>
        <th align="center"><label>DockerViz<br></br>Upload your docker-compose file for graph</label></th>
        <tr><div align="center" id = 'fileName'></div></tr>
        </table>
        <tr><td align="center"><label class="custom-file-upload">
        <input type="file" onChange={onInputChange}/>
        Upload File
        </label>&nbsp;&nbsp;&nbsp;&nbsp;
        <label class="custom-file-upload">
            <input type= "submit"/>Send
        </label></td></tr>
     </form>
     <div>
     <img src={`data:;base64,${image}`} id = 'response' hidden/>
     </div>
    </center>)
};
